-- Tenancy: the BRAND_PREDICATE sentinel (below) is replaced with `brand_id = ?` by the serving seam.
CREATE OR REPLACE VIEW iceberg.brain_serving.mv_metric_gross_revenue_month_slow AS
WITH base AS (
  SELECT
    brand_id,
    date_trunc('month', conversion_at) AS period,
    currency_code,
    channel,
    SUM(order_value_minor) AS gross_revenue_minor
  FROM iceberg.brain_serving.semantic_order
  WHERE conversion_at IS NOT NULL
    AND ${BRAND_PREDICATE}
